import{_ as r,o as d,c as a,a6 as e}from"./chunks/framework.DxlbIVIm.js";const o="/MyForbiddenWiki/images/characters/punk-girl-standing.png",u=JSON.parse('{"title":"龐克女孩 角色設定卡","description":"","frontmatter":{},"headers":[],"relativePath":"characters/punk-girl.md","filePath":"characters/punk-girl.md"}'),n={name:"characters/punk-girl.md"};function h(s,t,i,l,c,g){return d(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="龐克女孩-角色設定卡" tabindex="-1">龐克女孩 角色設定卡 <a class="header-anchor" href="#龐克女孩-角色設定卡" aria-label="Permalink to &quot;龐克女孩 角色設定卡&quot;">​</a></h1><hr><h2 id="角色圖像區" tabindex="-1">角色圖像區 <a class="header-anchor" href="#角色圖像區" aria-label="Permalink to &quot;角色圖像區&quot;">​</a></h2><div style="text-align:center;margin:0 auto 1rem;"><img src="'+o+'" alt="龐克女孩立繪｜標準站姿（白背景）" width="380" loading="lazy" decoding="async" style="max-width:min(380px, 100%);height:auto;"></div><blockquote><p>與提示詞索引對應：<code>龐克女孩提示詞.md</code>。</p></blockquote><hr><h2 id="角色標籤" tabindex="-1">角色標籤 <a class="header-anchor" href="#角色標籤" aria-label="Permalink to &quot;角色標籤&quot;">​</a></h2><p><strong>叛逆冷豔・外冷內熱</strong></p><hr><h2 id="基本屬性" tabindex="-1">基本屬性 <a class="header-anchor" href="#基本屬性" aria-label="Permalink to &quot;基本屬性&quot;">​</a></h2><table tabindex="0"><thead><tr><th>屬性</th><th>內容</th></tr></thead><tbody><tr><td><strong>性格</strong></td><td>叛逆不羈、外冷內熱、倔強不服輸、高度自我意識</td></tr><tr><td><strong>性慾欲望</strong></td><td>掌控欲強、嘴硬身體誠實、身體比意識先投降</td></tr><tr><td><strong>生日</strong></td><td>10 / 31</td></tr><tr><td><strong>喜好</strong></td><td>龐克搖滾、黑色美學、骷髏元素、一個人的空間、深夜</td></tr><tr><td><strong>口頭禪</strong></td><td>「關你什麼事」・「我沒事」・「隨便」</td></tr><tr><td><strong>特長</strong></td><td>看穿人心、行動果決、一眼辨別虛偽</td></tr><tr><td><strong>身高</strong></td><td>160 cm</td></tr><tr><td><strong>外貌</strong></td><td>黑色短波波頭・齊劉海・淺綠灰色虹膜・明顯黑眼圈・白皙正常膚色・略蒼白嘴唇・纖瘦身材</td></tr></tbody></table><hr><h2 id="外觀細節設定" tabindex="-1">外觀細節設定 <a class="header-anchor" href="#外觀細節設定" aria-label="Permalink to &quot;外觀細節設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>部位</th><th>設定</th></tr></thead><tbody><tr><td><strong>髮型</strong></td><td>黑色短波波頭、齊劉海、髮尾輕掃臉頰</td></tr><tr><td><strong>眼睛</strong></td><td>淺綠色偏灰的虹膜、大而銳利、明顯黑眼圈與眼袋</td></tr><tr><td><strong>膚色</strong></td><td>白皙偏正常膚色，非病態蒼白</td></tr><tr><td><strong>嘴唇</strong></td><td>略蒼白、低飽和粉色，幾乎不上色</td></tr><tr><td><strong>妝容</strong></td><td>哥德風暗色妝、刻意不修邊幅的自然感</td></tr><tr><td><strong>胸部</strong></td><td>B罩杯、略微豐滿、乳暈和乳頭較大呈暗粉棕色</td></tr><tr><td><strong>身材</strong></td><td>纖瘦、鎖骨明顯、腰線清晰</td></tr><tr><td><strong>陰唇</strong></td><td>較長且明顯突出</td></tr><tr><td><strong>陰毛</strong></td><td>刮除後淡淡短毛茬（有痕跡但不茂盛）</td></tr></tbody></table><hr><h2 id="標誌性配飾" tabindex="-1">標誌性配飾 <a class="header-anchor" href="#標誌性配飾" aria-label="Permalink to &quot;標誌性配飾&quot;">​</a></h2><table tabindex="0"><thead><tr><th>配飾</th><th>說明</th></tr></thead><tbody><tr><td><strong>黑色皮革項圈</strong></td><td>永遠不摘——這是她對自己的「契約」，代表自我認同與不被世界同化的宣言。即使在最私密的場合，項圈仍在。</td></tr><tr><td><strong>骷髏圖案黑T恤</strong></td><td>對世界的抗議與自我宣言，是她的標準外出服</td></tr><tr><td><strong>黑色百褶短裙</strong></td><td>看似矛盾的柔軟，但她把它穿出了攻擊性</td></tr><tr><td><strong>銀色釘釘皮腰帶＋鏈條</strong></td><td>視覺化的「盔甲」，代表對世界的防禦</td></tr><tr><td><strong>耳釘</strong></td><td>小巧的銀色耳釘，偶爾穿戴</td></tr></tbody></table><hr><h2 id="核心性格" tabindex="-1">核心性格 <a class="header-anchor" href="#核心性格" aria-label="Permalink to &quot;核心性格&quot;">​</a></h2><h3 id="叛逆、不服從權威" tabindex="-1">叛逆、不服從權威 <a class="header-anchor" href="#叛逆、不服從權威" aria-label="Permalink to &quot;叛逆、不服從權威&quot;">​</a></h3><p>對社會規範、傳統價值、主流審美都有明顯排斥感。討厭被說「應該怎樣」，越被管越想反著來。把龐克／哥德打扮視為「對世界的抗議」與「自我宣言」。</p><h3 id="外冷內熱的獨行者" tabindex="-1">外冷內熱的獨行者 <a class="header-anchor" href="#外冷內熱的獨行者" aria-label="Permalink to &quot;外冷內熱的獨行者&quot;">​</a></h3><p>表面看起來冷酷、難以親近，甚至帶有攻擊性氣場。內心其實有熱情與執著，但不會輕易表達給他人看。習慣一個人行動，不主動尋求群體的認同或保護。</p><h3 id="倔強與抗壓" tabindex="-1">倔強與抗壓 <a class="header-anchor" href="#倔強與抗壓" aria-label="Permalink to &quot;倔強與抗壓&quot;">​</a></h3><p>就算感到疲倦或受傷，也會選擇咬牙撐住，不願在他人面前倒下。有很強的「不想輸、不想被看扁」的意識。對自己的要求嚴格，容易自我苛責，但不會坦白承認。</p><h3 id="自我意識與審美主張強烈" tabindex="-1">自我意識與審美主張強烈 <a class="header-anchor" href="#自我意識與審美主張強烈" aria-label="Permalink to &quot;自我意識與審美主張強烈&quot;">​</a></h3><p>對自己喜歡的風格非常清楚。不在乎他人怎麼評價她的穿著，甚至會因為被批評而更強化自己的風格。把「保持自我風格」視為一種尊嚴與原則。</p><hr><h2 id="情緒與表情特徵" tabindex="-1">情緒與表情特徵 <a class="header-anchor" href="#情緒與表情特徵" aria-label="Permalink to &quot;情緒與表情特徵&quot;">​</a></h2><h3 id="常態表情" tabindex="-1">常態表情 <a class="header-anchor" href="#常態表情" aria-label="Permalink to &quot;常態表情&quot;">​</a></h3><p>眼神銳利、審視、挑戰感強，像是在說「你有什麼意見？」。很少露出溫柔笑容或可愛表情，給人距離感與壓迫感。</p><h3 id="情緒表達方式" tabindex="-1">情緒表達方式 <a class="header-anchor" href="#情緒表達方式" aria-label="Permalink to &quot;情緒表達方式&quot;">​</a></h3><p>生氣、反感、不耐煩都表現在眼神與語氣上，很直接、不包裝。對不喜歡的事情會明白說「不」。喜歡和信任的人面前，語氣會明顯柔和、毒舌減少，但不太會突然變甜。</p><h3 id="隱藏的疲憊感" tabindex="-1">隱藏的疲憊感 <a class="header-anchor" href="#隱藏的疲憊感" aria-label="Permalink to &quot;隱藏的疲憊感&quot;">​</a></h3><p>黑眼圈與眼袋表示她長期處於壓力或消耗狀態。這種疲憊感沒有被表現為「脆弱」，而是與倔強、強硬混在一起，形成一種「累但還在撐」的氣質。</p><hr><h2 id="人際互動模式" tabindex="-1">人際互動模式 <a class="header-anchor" href="#人際互動模式" aria-label="Permalink to &quot;人際互動模式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>對象</th><th>態度</th></tr></thead><tbody><tr><td><strong>陌生人</strong></td><td>冷淡、帶防備與敵意。對多管閒事、帶偏見的人直接冷臉或反嗆</td></tr><tr><td><strong>朋友／信任對象</strong></td><td>嘴硬毒舌，但實際會默默幫忙。關心方式偏實際，而非甜言蜜語</td></tr><tr><td><strong>喜歡的人</strong></td><td>嘴上絕不承認，但收起尖刺、語氣轉柔；行動上比任何人都更在乎對方</td></tr><tr><td><strong>對自己</strong></td><td>高度自我要求，習慣把問題自己消化，不輕易被人同情</td></tr></tbody></table><hr><h2 id="價值觀" tabindex="-1">價值觀 <a class="header-anchor" href="#價值觀" aria-label="Permalink to &quot;價值觀&quot;">​</a></h2><ul><li><strong>自由至上</strong>：把「做自己」看得比「被認同」更重要。寧可被誤解，也不想為了取悅別人而改變本性。</li><li><strong>不信任虛偽與權威</strong>：對虛偽的人、空洞的規則、偽善的道德觀極度反感。</li><li><strong>對少數真心的人極度珍惜</strong>：一旦認定某人是重要存在，就會長期守護對方，雖然嘴上絕不說。</li></ul><hr><h2 id="性慾特質與親密關係反應" tabindex="-1">性慾特質與親密關係反應 <a class="header-anchor" href="#性慾特質與親密關係反應" aria-label="Permalink to &quot;性慾特質與親密關係反應&quot;">​</a></h2><h3 id="掌控欲" tabindex="-1">掌控欲 <a class="header-anchor" href="#掌控欲" aria-label="Permalink to &quot;掌控欲&quot;">​</a></h3><p>在親密關係中需要掌控感，偏好主動、在上方的位置（騎乘位）。被動局面讓她不安，但在信任的人面前會逐漸放開。</p><h3 id="嘴硬身體誠實" tabindex="-1">嘴硬身體誠實 <a class="header-anchor" href="#嘴硬身體誠實" aria-label="Permalink to &quot;嘴硬身體誠實&quot;">​</a></h3><p>這是她最核心的親密反應特質。無論意識上多麼抗拒，身體的反應永遠比嘴更誠實。她會努力壓制——但壓制得越用力，崩潰時的反差就越大。</p><h3 id="情緒防線崩潰的層次" tabindex="-1">情緒防線崩潰的層次 <a class="header-anchor" href="#情緒防線崩潰的層次" aria-label="Permalink to &quot;情緒防線崩潰的層次&quot;">​</a></h3><table tabindex="0"><thead><tr><th>階段</th><th>她的狀態</th></tr></thead><tbody><tr><td><strong>插入前</strong></td><td>防線完整，裝作沒事，但已微微臉紅</td></tr><tr><td><strong>剛插入入口</strong></td><td>主動壓制・咬唇撐住・掙扎感</td></tr><tr><td><strong>一口氣插到底</strong></td><td>瞬間破防・眼睛猛睜・不自主倒吸氣</td></tr><tr><td><strong>慢速抽插中</strong></td><td>被慢慢磨垮・眼神渙散・不情願地沉進去</td></tr><tr><td><strong>高潮</strong></td><td>徹底繳械・什麼都壓不住了</td></tr><tr><td><strong>誇張高潮</strong></td><td>形象全毀・舌出・眼翻白・口水不在乎</td></tr></tbody></table><h3 id="項圈的象徵" tabindex="-1">項圈的象徵 <a class="header-anchor" href="#項圈的象徵" aria-label="Permalink to &quot;項圈的象徵&quot;">​</a></h3><p>即使在最私密、最失控的時刻，項圈永遠戴著。這是她對自己身份認同的最後錨點——「我可以崩潰，但我還是我。」</p><hr><h2 id="角色簡介" tabindex="-1">角色簡介 <a class="header-anchor" href="#角色簡介" aria-label="Permalink to &quot;角色簡介&quot;">​</a></h2><p>她是一個用龐克外殼武裝自己、拒絕被世界馴化的叛逆女孩。</p><p>短黑波波頭、銳利的淺綠灰色眼睛、始終存在的黑眼圈——這張臉不是故意做出來的酷，而是她真正活著的樣子：疲憊、緊繃、但始終倔強地站著。</p><p>她的項圈不只是裝飾。那是她和自己訂下的契約：「我不會因為任何人改變我自己。」這個契約她一直遵守著——即使在最親密的時刻，脫掉了所有武裝，那條項圈仍然在。</p><p>表面上，她冷漠、具有攻擊性氣場、讓人不敢輕易靠近。但那不是她的本質，只是她的盔甲。盔甲之下，是一個對少數真心的人極度珍惜、用行動而非語言表達在乎的人。</p><p>她不會說「我喜歡你」。但她會在你累的時候默默陪著、在你被欺負的時候第一個衝出去、在你最脆弱的時候說「有什麼大不了的」然後把你拉起來。</p><p>在親密關係裡，她需要掌控感——因為失控讓她害怕。但一旦她決定信任一個人，那個人就會看到她最真實的樣子：咬著下唇撐住、眼角泛著水光、臉頰漲得通紅、嘴上說著「我還好」——而身體早就已經坦白了一切。</p><p><strong>她是一個用龐克外殼武裝自己、拒絕被世界馴化的叛逆女孩：眼神銳利、態度強硬、心裡疲憊卻仍倔強地站著，不願向任何人示弱——除了那個讓她願意慢慢摘下盔甲的人。</strong></p><hr><h2 id="對應提示詞文件索引" tabindex="-1">對應提示詞文件索引 <a class="header-anchor" href="#對應提示詞文件索引" aria-label="Permalink to &quot;對應提示詞文件索引&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件</th><th>說明</th></tr></thead><tbody><tr><td><code>龐克女孩提示詞.md</code></td><td>基礎外觀・白背景站姿版</td></tr><tr><td><code>龐克女孩裸體提示詞.md</code></td><td>全裸基礎版</td></tr><tr><td><code>龐克女孩黑色內衣褲提示詞.md</code></td><td>內衣版</td></tr><tr><td><code>龐克女孩黑色比基尼提示詞.md</code></td><td>比基尼版</td></tr><tr><td><code>龐克女孩皮外套穿搭提示詞.md</code></td><td>皮外套穿搭版</td></tr><tr><td><code>龐克女孩全裸女上位姿勢夜晚臥室版提示詞.md</code></td><td>女上位・夜晚臥室・六階段表情版</td></tr><tr><td><code>龐克女孩全裸女上位陰莖外露夜光無液體版提示詞.md</code></td><td>女上位・陰莖外露版</td></tr><tr><td><code>龐克女孩全裸靠牆背面姿勢提示詞.md</code></td><td>靠牆背面版</td></tr><tr><td><code>龐克女孩裸體溫泉夜晚石板彎腰頭撐地翹臀害羞提示詞.md</code></td><td>溫泉版</td></tr><tr><td><code>龐克女孩做愛CG場景設定.md</code></td><td>四場CG完整場景設定（床上・酒吧・溫泉・泳池）</td></tr><tr><td><code>龐克女孩性格設定.md</code></td><td>完整性格文字設定</td></tr></tbody></table>',63)])])}const p=r(n,[["render",h]]);export{u as __pageData,p as default};
